const alumnos = $input.all();
const resultados = [];

for (const item of alumnos) {
  const d = item.json;

  // Pesos de la media ponderada (ajustar segun criterios del centro)
  // Estos valores definen cuanto pesa cada componente en la nota final
  const pesoExamen = 0.5;        // 50% examenes
  const pesoTrabajo = 0.3;       // 30% trabajos y tareas
  const pesoParticipacion = 0.2; // 20% participacion en clase

  // parseFloat convierte el texto a numero, || 0 pone un 0 si no hay nota
  const notaExamen = parseFloat(d.nota_examen) || 0;
  const notaTrabajo = parseFloat(d.nota_trabajo) || 0;
  const notaParticipacion = parseFloat(d.nota_participacion) || 0;

  // Calculo de la media ponderada
  const media = (notaExamen * pesoExamen) + (notaTrabajo * pesoTrabajo) + (notaParticipacion * pesoParticipacion);
  const mediaRedondeada = Math.round(media * 100) / 100;

  // Asignacion de calificacion textual segun la escala del sistema educativo
  let calificacion = 'Insuficiente'; // menos de 5
  if (media >= 9) calificacion = 'Sobresaliente';
  else if (media >= 7) calificacion = 'Notable';
  else if (media >= 6) calificacion = 'Bien';
  else if (media >= 5) calificacion = 'Suficiente';

  resultados.push({
    json: {
      alumno: d.alumno,
      nota_examen: notaExamen,
      nota_trabajo: notaTrabajo,
      nota_participacion: notaParticipacion,
      media_final: mediaRedondeada,
      calificacion: calificacion,
      aprobado: media >= 5 ? 'Si' : 'No'
    }
  });
}

return resultados;
